  1→import { useEffect, useRef } from 'react';
  2→import './search_bar.scss';
  3→
  4→export interface BreadcrumbItem {
  5→  label: string;
  6→  onBack: () => void;
  7→}
  8→
  9→interface SearchBarProps {
 10→  value: string;
 11→  onChange: (value: string) => void;
 12→  placeholder?: string;
 13→  activeDescendantId?: string;
 14→  breadcrumbs?: BreadcrumbItem[];
 15→}
 16→
 17→export function SearchBar({
 18→  value,
 19→  onChange,
 20→  placeholder = 'Search...',
 21→  activeDescendantId,
 22→  breadcrumbs,
 23→}: SearchBarProps) {
 24→  const inputRef = useRef<HTMLInputElement>(null);
 25→
 26→  useEffect(() => {
 27→    inputRef.current?.focus();
 28→  }, []);
 29→
 30→  useEffect(() => {
 31→    if (!breadcrumbs || breadcrumbs.length === 0) return;
 32→    const lastCrumb = breadcrumbs[breadcrumbs.length - 1];
 33→    if (!lastCrumb) return;
 34→    const { onBack } = lastCrumb;
 35→
 36→    function handleKeyDown(e: KeyboardEvent) {
 37→      if (e.key === 'Escape') {
 38→        e.preventDefault();
 39→        if (value) {
 40→          onChange('');
 41→        } else {
 42→          onBack();
 43→        }
 44→      }
 45→    }
 46→
 47→    window.addEventListener('keydown', handleKeyDown);
 48→    return () => window.removeEventListener('keydown', handleKeyDown);
 49→  }, [
 50→    breadcrumbs,
 51→    onChange,
 52→    value,
 53→  ]);
 54→
 55→  return (
 56→    <div className="search-bar" role="search">
 57→      <svg
 58→        className="search-bar__icon"
 59→        width="16"
 60→        height="16"
 61→        viewBox="0 0 16 16"
 62→        fill="none"
 63→        xmlns="http://www.w3.org/2000/svg"
 64→      >
 65→        <circle cx="7" cy="7" r="4.5" stroke="currentColor" strokeWidth="1.5" />
 66→        <line
 67→          x1="10.5"
 68→          y1="10.5"
 69→          x2="14"
 70→          y2="14"
 71→          stroke="currentColor"
 72→          strokeWidth="1.5"
 73→          strokeLinecap="round"
 74→        />
 75→      </svg>
 76→      {breadcrumbs && breadcrumbs.length > 0 && (
 77→        <div className="search-bar__breadcrumbs">
 78→          {breadcrumbs.map((crumb, i) => (
 79→            <button
 80→              key={i}
 81→              className="search-bar__breadcrumb"
 82→              onClick={crumb.onBack}
 83→              type="button"
 84→              aria-label={`Back to ${crumb.label}`}
 85→            >
 86→              {crumb.label}
 87→              {i < breadcrumbs.length - 1 && (
 88→                <svg
 89→                  className="search-bar__breadcrumb-chevron"
 90→                  width="8"
 91→                  height="8"
 92→                  viewBox="0 0 8 8"
 93→                  fill="none"
 94→                >
 95→                  <path
 96→                    d="M2.5 1.5L5.5 4L2.5 6.5"
 97→                    stroke="currentColor"
 98→                    strokeWidth="1.2"
 99→                    strokeLinecap="round"
100→                    strokeLinejoin="round"
101→                  />
102→                </svg>
103→              )}
104→            </button>
105→          ))}
106→        </div>
107→      )}
108→      <input
109→        ref={inputRef}
110→        className="search-bar__input"
111→        type="text"
112→        value={value}
113→        onChange={e => onChange(e.target.value)}
114→        placeholder={placeholder}
115→        role="combobox"
116→        aria-expanded={true}
117→        aria-controls="command-list"
118→        aria-activedescendant={activeDescendantId}
119→        aria-label="Search commands"
120→        spellCheck={false}
121→        autoComplete="off"
122→      />
123→    </div>
124→  );
125→}
