 92→export function App() {
 93→  const [query, setQuery] = useState('');
 94→  const [selectedIndex, setSelectedIndex] = useState(0);
 95→  const [actionsOpen, setActionsOpen] = useState(false);
 96→  const [drilledItem, setDrilledItem] = useState<ListItemData | null>(null);
 97→
 98→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
 99→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
100→  const selectedItem = drilledItem ?? allItems[selectedIndex];
101→
102→  const handleQueryChange = useCallback((value: string) => {
103→    setQuery(value);
104→    setSelectedIndex(0);
105→    setActionsOpen(false);
106→  }, []);
107→
108→  const handleActiveIndexChange = useCallback((index: number) => {
109→    setSelectedIndex(index);
110→    setActionsOpen(false);
111→  }, []);
112→
113→  const handleDrillIn = useCallback(() => {
114→    const item = allItems[selectedIndex];
115→    if (item) {
116→      setDrilledItem(item);
117→      setQuery('');
118→      setActionsOpen(false);
119→    }
120→  }, [
121→    allItems,
122→    selectedIndex,
123→  ]);
124→
125→  const handleDrillBack = useCallback(() => {
126→    setDrilledItem(null);
127→    setQuery('');
128→    setSelectedIndex(0);
129→    setActionsOpen(false);
130→  }, []);
131→
132→  const breadcrumbs: BreadcrumbItem[] | undefined = drilledItem
133→    ? [
134→        {
135→          label: 'Raycast',
136→          onBack: handleDrillBack,
137→        },
138→        {
139→          label: drilledItem.title,
140→          onBack: handleDrillBack,
141→        },
142→      ]
143→    : undefined;
144→
145→  const toggleActions = useCallback(() => {
146→    setActionsOpen(prev => !prev);
147→  }, []);
148→
149→  const closeActions = useCallback(() => {
150→    setActionsOpen(false);
151→  }, []);
152→
153→  useEffect(() => {
154→    function handleKeyDown(e: KeyboardEvent) {
155→      if (e.key === 'k' && e.metaKey) {
156→        e.preventDefault();
157→        setActionsOpen(prev => !prev);
158→      }
159→    }
160→
161→    window.addEventListener('keydown', handleKeyDown);
162→    return () => window.removeEventListener('keydown', handleKeyDown);
163→  }, []);
164→
165→  const detail = selectedItem?.detail;
166→
167→  const dropdownActions = useMemo(
168→    () => [
169→      {
170→        label: 'Open',
171→        shortcut: <Kbd keys={['↵']} />,
172→      },
173→      {
174→        label: 'Copy Name',
175→        shortcut: (
176→          <Kbd
177→            keys={[
178→              '⌘',
179→              'C',
180→            ]}
181→          />
182→        ),
183→      },
184→      {
185→        label: 'Show Detail',
186→        shortcut: (
187→          <Kbd
188→            keys={[
189→              '⌘',
190→              'D',
191→            ]}
192→          />
193→        ),
194→      },
195→      {
196→        label: 'Pin to Top',
197→        shortcut: (
198→          <Kbd
199→            keys={[
200→              '⌘',
201→              'P',
202→            ]}
203→          />
204→        ),
205→      },
206→    ],
207→    [],
208→  );
209→
210→  return (
211→    <CommandPalette>
212→      <SearchBar
213→        value={query}
214→        onChange={handleQueryChange}
215→        activeDescendantId={
216→          allItems.length > 0 ? `list-item-${selectedIndex}` : undefined
217→        }
218→        breadcrumbs={breadcrumbs}
219→      />
220→      <div
221→        className={`command-palette__body${detail ? ' command-palette__body--has-detail' : ''}`}
222→      >
223→        <div className="command-palette__list-container">
224→          {allItems.length === 0 ? (
225→            <EmptyState
226→              icon={<SearchIcon />}
227→              title="No Results"
228→              description="Try a different search term"
229→            />
230→          ) : (
231→            <List
232→              itemCount={allItems.length}
233→              onActiveIndexChange={handleActiveIndexChange}
234→              onAction={handleDrillIn}
235→            >
236→              {(() => {
237→                let globalIndex = 0;
238→                return filtered.map(section => (
239→                  <ListSection key={section.title} title={section.title}>
240→                    {section.items.map(item => {
241→                      const idx = globalIndex++;
242→                      return (
243→                        <ListItem
244→                          key={item.id}
245→                          index={idx}
246→                          title={item.title}
247→                          subtitle={item.subtitle}
248→                          icon={item.icon}
249→                          accessories={item.accessories}
250→                        />
251→                      );
252→                    })}
253→                  </ListSection>
254→                ));
255→              })()}
256→            </List>
257→          )}
258→        </div>
259→        {detail && (
260→          <Detail
261→            markdown={detail.markdown}
262→            metadata={
263→              detail.metadata ? (
264→                <DetailMetadata>
265→                  {detail.metadata.map(renderMetadataEntry)}
266→                </DetailMetadata>
267→              ) : undefined
268→            }
269→          />
270→        )}
271→      </div>
272→      <ActionPanel
273→        actions={[
274→          {
275→            label: 'Open',
276→            shortcut: <Kbd keys={['↵']} />,
277→          },
278→          {
279→            label: 'Actions',
280→            shortcut: (
281→              <Kbd
282→                keys={[
283→                  '⌘',
284→                  'K',
285→                ]}
286→              />
287→            ),
288→            onClick: toggleActions,
289→          },
290→        ]}
291→        dropdownOpen={actionsOpen}
292→        dropdownActions={dropdownActions}
293→        onDropdownClose={closeActions}
294→      />
295→    </CommandPalette>
296→  );
297→}
